using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old property name so existing documents are still found.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 2: Id format changed from "EntityType|Key" to just "Key".
        // Preserve the old "Blog|{Id}" format for existing documents.
        modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasJsonPropertyName("id");

        // Breaking change 3: HasIndex() now throws for Cosmos provider.
        // Removed: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
        // Cosmos indexes are managed via indexing policy, not EF HasIndex.
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change 2 (cont.): Restore the old id format "EntityType|Key"
        // so existing documents with "Blog|1" ids are still matched.
        configurationBuilder.Conventions.Add(_ =>
            new IdFormatConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

// Convention to preserve EF Core 8 id format: "EntityType|KeyValue"
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using Microsoft.EntityFrameworkCore.Metadata.Conventions;
class IdFormatConvention : IModelFinalizingConvention
{
    public void ProcessModelFinalizing(IConventionModelBuilder modelBuilder,
        IConventionContext<IConventionModelBuilder> context)
    {
        foreach (var entityType in modelBuilder.Metadata.GetEntityTypes())
        {
            entityType.SetCosmosIdProperty(null);
        }
    }
}

