using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Default discriminator property renamed "$type".
            // Preserve old property name so existing documents are found.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: Id format changed from "EntityType|Key" to just "Key".
            // Use a value converter to preserve the old "Blog|{Id}" format
            // so existing documents with id "Blog|1" are still matched.
            entity.Property(b => b.Id)
                .HasConversion(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring(5) : v);

            // Breaking change 3: HasIndex() now throws for Cosmos provider.
            // Removed — Cosmos indexes are managed via indexing policy, not EF.
            // Was: entity.HasIndex(b => b.Name);
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

